792 Instruction *InstCombinerImpl::visitVAEndInst(VAEndInst &I) {
793   removeTriviallyEmptyRange(I, *this, [](const IntrinsicInst &I) {
794     return I.getIntrinsicID() == Intrinsic::vastart ||
795            I.getIntrinsicID() == Intrinsic::vacopy;
796   });
797   return nullptr;
